// Note: Metadata must be in a separate layout file or server component if using "use client"
// For this example, I'm keeping the logic focused on the 3D implementation.

/**
 * A simple wrapper to apply 3D tilt logic using CSS variables
 */
const TiltWrapper = ({ children }: { children: React.ReactNode }) => {
  const cardRef = useRef<HTMLDivElement>(null);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!cardRef.current) return;
    const card = cardRef.current;
    const rect = card.getBoundingClientRect();
    
    // Calculate mouse position relative to card center
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;
    
    // Calculate rotation (adjust the divisor 10 to change tilt intensity)
    const rotateX = (centerY - y) / 10;
    const rotateY = (x - centerX) / 10;

    card.style.setProperty("--rotateX", `${rotateX}deg`);
    card.style.setProperty("--rotateY", `${rotateY}deg`);
  };

  const handleMouseLeave = () => {
    if (!cardRef.current) return;
    cardRef.current.style.setProperty("--rotateX", `0deg`);
    cardRef.current.style.setProperty("--rotateY", `0deg`);
  };

  return (
    <div 
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      className="tilt-container transition-transform duration-200 ease-out"
      style={{
        perspective: "1000px",
        transform: "rotateX(var(--rotateX, 0deg)) rotateY(var(--rotateY, 0deg))",
        transformStyle: "preserve-3d"
      }}
    >
      <div style={{ transform: "translateZ(20px)" }}>
        {children}
      </div>
    </div>
  );
};

